Here's a complete test class for `DataFetcher` using modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // Helper: create a DataFetcher with a fake HTTP handler
    private static DataFetcher CreateFetcher(HttpMessageHandler handler)
        => new(new HttpClient(handler));

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello world"),
        });
        var fetcher = CreateFetcher(handler);

        // Act
        var result = await fetcher.FetchAsync(
            "https://example.com/data", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFoundResponse_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.NotFound));
        var fetcher = CreateFetcher(handler);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/missing", _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.OK));
        var fetcher = CreateFetcher(handler);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/data", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_PropagatesTimeoutCancellation()
    {
        // Arrange — handler delays longer than the token allows
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.OK),
            simulatedDelay: TimeSpan.FromSeconds(30));
        var fetcher = CreateFetcher(handler);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com/slow", cts.Token));
    }

    /// <summary>Minimal HttpMessageHandler stub for testing.</summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        private readonly TimeSpan _delay;

        public FakeHandler(HttpResponseMessage response, TimeSpan simulatedDelay = default)
        {
            _response = response;
            _delay = simulatedDelay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken);
            }

            cancellationToken.ThrowIfCancellationRequested();
            return _response;
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Async tests** | `async Task` return type — MSTest awaits them natively |
| **Timeouts** | `[Timeout(5000)]` + `_testContext.CancellationToken` — the token is auto-cancelled when the timeout expires |
| **Cancellation** | Pass a pre-cancelled `CancellationTokenSource` and assert `TaskCanceledException` |
| **Timeout propagation** | Short-lived CTS + slow handler proves the token flows through to `HttpClient` |
| **Exception testing** | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |
| **Sealed class** | Performance + design clarity |
| **Constructor-injected TestContext** | Enables `readonly` fields, works with nullability |

The `FakeHandler` avoids any external mocking library — it's a simple `HttpMessageHandler` stub that returns a canned response with an optional delay for timeout tests.
